mapper.select:
SELECT c.id, c.contact_id, COALESCE(u.username, c.nickname) AS username, COALESCE(u.email, c.email) AS email, c.nickname, c.group_name, c.created_at FROM contacts c LEFT JOIN users u ON c.contact_id = u.id WHERE c.owner_id = #{ownerId}
AND c.group_name = #{groupName}
ORDER BY COALESCE(u.username, c.nickname)

mapper.update:
UPDATE contacts
SET nickname = #{nickname}, group_name = #{groupName}, email = #{email}
WHERE id = #{id} AND owner_id = #{ownerId}
